  1→/**
  2→ * Verification pipeline: pure core functions for claim-vs-reality comparison.
  3→ *
  4→ * Pipeline: receiveEvent -> gatherSignals -> compareClaimVsReality -> createObservation
  5→ *
  6→ * All functions in this module are pure (no IO). The effect shell lives in observer-route.ts.
  7→ */
  8→
  9→import type { ExternalSignal, GatherSignalsResult } from "./external-signals";
 10→
 11→// ---------------------------------------------------------------------------
 12→// Types
 13→// ---------------------------------------------------------------------------
 14→
 15→export type Verdict = "match" | "mismatch" | "inconclusive";
 16→
 17→export type VerificationResult = {
 18→  verdict: Verdict;
 19→  severity: "info" | "warning" | "conflict";
 20→  verified: boolean;
 21→  text: string;
 22→  source?: string;
 23→};
 24→
 25→export type IntentStatus = "completed" | "failed" | string;
 26→
 27→export type IntentSignals = {
 28→  status: IntentStatus;
 29→  goal: string;
 30→  hasTrace: boolean;
 31→};
 32→
 33→export type DecisionStatus = "confirmed" | "superseded" | string;
 34→
 35→export type DecisionSignals = {
 36→  status: DecisionStatus;
 37→  summary: string;
 38→  completedTaskCount: number;
 39→};
 40→
 41→export type ObservationPeerReviewSignals = {
 42→  originalText: string;
 43→  originalSeverity: "info" | "warning" | "conflict";
 44→  sourceAgent: string;
 45→  relatedTaskCount: number;
 46→  relatedDecisionCount: number;
 47→};
 48→
 49→// ---------------------------------------------------------------------------
 50→// Pure comparison: claim vs reality for task completion
 51→// ---------------------------------------------------------------------------
 52→
 53→export function compareTaskCompletion(
 54→  signalsResult: GatherSignalsResult,
 55→): VerificationResult {
 56→  // No commits linked -> inconclusive
 57→  if (!signalsResult.hasCommits || signalsResult.signals.length === 0) {
 58→    return {
 59→      verdict: "inconclusive",
 60→      severity: "info",
 61→      verified: false,
 62→      text: "Unable to verify task completion: no external signals (commits or CI) found for this task.",
 63→    };
 64→  }
 65→
 66→  // Check CI status across all signals
 67→  const ciSignals = signalsResult.signals.filter(
 68→    (signal) => signal.ciStatus !== "unknown",
 69→  );
 70→
 71→  // All signals unknown -> inconclusive
 72→  if (ciSignals.length === 0) {
 73→    return {
 74→      verdict: "inconclusive",
 75→      severity: "info",
 76→      verified: false,
 77→      text: "Unable to verify task completion: CI status unavailable for linked commits.",
 78→      source: signalsResult.signals[0]?.source,
 79→    };
 80→  }
 81→
 82→  // Any failing CI -> mismatch
 83→  const failingSignals = ciSignals.filter(
 84→    (signal) => signal.ciStatus === "failure",
 85→  );
 86→
 87→  if (failingSignals.length > 0) {
 88→    const failingShas = failingSignals.map((s) => s.sha.slice(0, 8)).join(", ");
 89→    return {
 90→      verdict: "mismatch",
 91→      severity: "conflict",
 92→      verified: false,
 93→      text: `Task marked as completed but CI is failing for commit(s): ${failingShas}. Claim does not match reality.`,
 94→      source: failingSignals[0]?.source,
 95→    };
 96→  }
 97→
 98→  // Any pending CI -> inconclusive (not verified yet)
 99→  const pendingSignals = ciSignals.filter(
100→    (signal) => signal.ciStatus === "pending",
101→  );
102→
103→  if (pendingSignals.length > 0) {
104→    return {
105→      verdict: "inconclusive",
106→      severity: "info",
107→      verified: false,
108→      text: "Task completion verification pending: CI checks still running.",
109→      source: pendingSignals[0]?.source,
110→    };
111→  }
112→
113→  // All passing -> match
114→  const source = ciSignals[0]?.source;
115→  return {
116→    verdict: "match",
117→    severity: "info",
118→    verified: true,
119→    text: "Task completion verified: all linked CI checks are passing.",
120→    source,
121→  };
122→}
123→
124→// ---------------------------------------------------------------------------
125→// Pure comparison: intent completion verification
126→// ---------------------------------------------------------------------------
127→
128→export function compareIntentCompletion(
129→  signals: IntentSignals,
130→): VerificationResult {
131→  if (signals.status === "completed") {
132→    return {
133→      verdict: "match",
134→      severity: "info",
135→      verified: true,
136→      text: `Intent completed successfully: ${signals.goal}`,
137→      source: signals.hasTrace ? "trace" : undefined,
138→    };
139→  }
140→
141→  if (signals.status === "failed") {
142→    return {
143→      verdict: "mismatch",
144→      severity: "warning",
145→      verified: false,
146→      text: `Intent failed: ${signals.goal}`,
147→      source: signals.hasTrace ? "trace" : undefined,
148→    };
149→  }
150→
151→  return {
152→    verdict: "inconclusive",
153→    severity: "info",
154→    verified: false,
155→    text: `Intent in unexpected status '${signals.status}': ${signals.goal}`,
156→  };
157→}
158→
159→// ---------------------------------------------------------------------------
160→// Pure comparison: decision confirmation/supersession verification
161→// ---------------------------------------------------------------------------
162→
163→export function compareDecisionConfirmation(
164→  signals: DecisionSignals,
165→): VerificationResult {
166→  if (signals.status === "confirmed") {
167→    if (signals.completedTaskCount === 0) {
168→      return {
169→        verdict: "inconclusive",
170→        severity: "info",
171→        verified: false,
172→        text: `Decision confirmed: "${signals.summary}". No completed tasks found in workspace to verify alignment.`,
173→      };
174→    }
175→
176→    return {
177→      verdict: "match",
178→      severity: "info",
179→      verified: true,
180→      text: `Decision confirmed: "${signals.summary}". Found ${signals.completedTaskCount} completed task(s) in workspace. Alignment check performed.`,
181→    };
182→  }
183→
184→  if (signals.status === "superseded") {
185→    if (signals.completedTaskCount === 0) {
186→      return {
187→        verdict: "inconclusive",
188→        severity: "info",
189→        verified: false,
190→        text: `Decision superseded: "${signals.summary}". No completed tasks found that may be affected.`,
191→      };
192→    }
193→
194→    return {
195→      verdict: "mismatch",
196→      severity: "warning",
197→      verified: false,
198→      text: `Decision superseded: "${signals.summary}". Found ${signals.completedTaskCount} completed task(s) that may now be based on an outdated decision. Review implementations for staleness.`,
199→    };
200→  }
201→
202→  return {
203→    verdict: "inconclusive",
204→    severity: "info",
205→    verified: false,
206→    text: `Decision in unexpected status '${signals.status}': "${signals.summary}"`,
207→  };
208→}
209→
210→// ---------------------------------------------------------------------------
211→// Pure comparison: observation peer review
212→// ---------------------------------------------------------------------------
213→
214→export function compareObservationPeerReview(
215→  signals: ObservationPeerReviewSignals,
216→): VerificationResult {
217→  const hasContext = signals.relatedTaskCount > 0 || signals.relatedDecisionCount > 0;
218→
219→  if (!hasContext) {
220→    return {
221→      verdict: "inconclusive",
222→      severity: "info",
223→      verified: false,
224→      text: `Peer review of ${signals.sourceAgent} observation: "${signals.originalText}". No related tasks or decisions found in workspace to cross-check this claim.`,
225→    };
226→  }
227→
228→  // When context exists, cross-check severity against workspace state
229→  if (signals.originalSeverity === "conflict") {
230→    return {
231→      verdict: "match",
232→      severity: "warning",
233→      verified: false,
234→      text: `Peer review of ${signals.sourceAgent} observation: "${signals.originalText}". Found ${signals.relatedTaskCount} task(s) and ${signals.relatedDecisionCount} decision(s) in workspace. Conflict claim requires human review.`,
235→    };
236→  }
237→
238→  if (signals.originalSeverity === "warning") {
239→    return {
240→      verdict: "match",
241→      severity: "info",
242→      verified: true,
243→      text: `Peer review of ${signals.sourceAgent} observation: "${signals.originalText}". Found ${signals.relatedTaskCount} task(s) and ${signals.relatedDecisionCount} decision(s) in workspace. Warning acknowledged and cross-checked.`,
244→    };
245→  }
246→
247→  return {
248→    verdict: "match",
249→    severity: "info",
250→    verified: true,
251→    text: `Peer review of ${signals.sourceAgent} observation: "${signals.originalText}". Cross-checked against ${signals.relatedTaskCount} task(s) and ${signals.relatedDecisionCount} decision(s).`,
252→  };
253→}
