255→export function compareCommitStatus(
256→  signalsResult: GatherSignalsResult,
257→): VerificationResult {
258→  // No CI signals available -> inconclusive
259→  if (signalsResult.signals.length === 0) {
260→    return {
261→      verdict: "inconclusive",
262→      severity: "info",
263→      verified: false,
264→      text: "Commit recorded: no CI status available for verification.",
265→    };
266→  }
267→
268→  const ciSignals = signalsResult.signals.filter(
269→    (signal) => signal.ciStatus !== "unknown",
270→  );
271→
272→  if (ciSignals.length === 0) {
273→    return {
274→      verdict: "inconclusive",
275→      severity: "info",
276→      verified: false,
277→      text: "Commit recorded: CI status unavailable.",
278→      source: signalsResult.signals[0]?.source,
279→    };
280→  }
281→
282→  const failingSignals = ciSignals.filter(
283→    (signal) => signal.ciStatus === "failure",
284→  );
285→
286→  if (failingSignals.length > 0) {
287→    return {
288→      verdict: "mismatch",
289→      severity: "warning",
290→      verified: false,
291→      text: `Commit has failing CI: ${failingSignals.map((s) => s.sha.slice(0, 8)).join(", ")}`,
292→      source: failingSignals[0]?.source,
293→    };
294→  }
295→
296→  const pendingSignals = ciSignals.filter(
297→    (signal) => signal.ciStatus === "pending",
298→  );
299→
300→  if (pendingSignals.length > 0) {
301→    return {
302→      verdict: "inconclusive",
303→      severity: "info",
304→      verified: false,
305→      text: "Commit verification pending: CI checks still running.",
306→      source: pendingSignals[0]?.source,
307→    };
308→  }
309→
310→  return {
311→    verdict: "match",
312→    severity: "info",
313→    verified: true,
314→    text: "Commit verified: all CI checks passing.",
315→    source: ciSignals[0]?.source,
316→  };
317→}
