  1→/**
  2→ * Observer HTTP route: POST /api/observe/:table/:id
  3→ *
  4→ * Effect shell that wires the verification pipeline to SurrealDB.
  5→ * Called by SurrealDB EVENTs when entity state transitions occur.
  6→ *
  7→ * Pipeline: receiveEvent -> gatherSignals -> compareClaimVsReality -> persistObservation
  8→ */
  9→
 10→import { RecordId, type Surreal } from "surrealdb";
 11→import { jsonResponse } from "../http/response";
 12→import { logError, logInfo } from "../http/observability";
 13→import { createObservation } from "../observation/queries";
 14→import { checkCiStatus } from "./external-signals";
 15→import { compareIntentCompletion, compareCommitStatus, compareDecisionConfirmation, compareObservationPeerReview } from "./verification-pipeline";
 16→import type { IntentSignals, DecisionSignals, ObservationPeerReviewSignals, VerificationResult } from "./verification-pipeline";
 17→import type { ServerDependencies } from "../runtime/types";
 18→import { runObserverAgent } from "../agents/observer/agent";
 19→import { runGraphScan } from "./graph-scan";
 20→
 21→// ---------------------------------------------------------------------------
 22→// Types
 23→// ---------------------------------------------------------------------------
 24→
 25→type SupportedTable = "task" | "intent" | "git_commit" | "decision" | "observation";
 26→
 27→const SUPPORTED_TABLES = new Set<string>([
 28→  "task",
 29→  "intent",
 30→  "git_commit",
 31→  "decision",
 32→  "observation",
 33→]);
 34→
 35→// ---------------------------------------------------------------------------
 36→// Shared observation persistence
 37→// ---------------------------------------------------------------------------
 38→
 39→async function persistVerificationObservation(
 40→  surreal: Surreal,
 41→  workspaceRecord: RecordId<"workspace", string>,
 42→  relatedRecord: RecordId,
 43→  verificationResult: VerificationResult,
 44→  defaultSource = "none",
 45→): Promise<void> {
 46→  const now = new Date();
 47→
 48→  const observationRecord = await createObservation({
 49→    surreal,
 50→    workspaceRecord,
 51→    text: verificationResult.text,
 52→    severity: verificationResult.severity,
 53→    sourceAgent: "observer_agent",
 54→    observationType: "validation",
 55→    now,
 56→    relatedRecord: relatedRecord as RecordId<"project" | "feature" | "task" | "decision" | "question", string>,
 57→  });
 58→
 59→  await surreal.query(
 60→    `UPDATE $obs SET verified = $verified, source = $source;`,
 61→    {
 62→      obs: observationRecord,
 63→      verified: verificationResult.verified,
 64→      source: verificationResult.source ?? defaultSource,
 65→    },
 66→  );
 67→}
 68→
 69→// ---------------------------------------------------------------------------
 70→// Route handler factory
 71→// ---------------------------------------------------------------------------
 72→
 73→export function createObserverRouteHandler(deps: ServerDependencies) {
 74→  return async (table: string, id: string, request: Request): Promise<Response> => {
 75→    if (!SUPPORTED_TABLES.has(table)) {
 76→      return jsonResponse({ error: "unsupported_table", table }, 400);
 77→    }
 78→
 79→    const supportedTable = table as SupportedTable;
 80→
 81→    try {
 82→      // Parse the EVENT body (the record itself, posted by SurrealDB EVENT)
 83→      const body = await request.json().catch(() => undefined);
 84→
 85→      logInfo("observer.event.received", "Observer event received", {
 86→        table: supportedTable,
 87→        id,
 88→      });
 89→
 90→      // Dispatch to the appropriate verification pipeline
 91→      switch (supportedTable) {
 92→        case "task":
 93→          await handleTaskVerification(deps, id, body);
 94→          break;
 95→
 96→        case "intent":
 97→          await handleIntentVerification(deps, id, body);
 98→          break;
 99→
100→        case "git_commit":
101→          await handleCommitVerification(deps, id, body);
102→          break;
103→
104→        case "decision":
105→          await handleDecisionVerification(deps, id, body);
106→          break;
107→
108→        case "observation":
109→          await handleObservationPeerReview(deps, id, body);
110→          break;
111→      }
112→
113→      return jsonResponse({ status: "ok" }, 200);
114→    } catch (error) {
115→      logError("observer.event.error", "Observer event processing failed", error);
116→      // Return 200 to prevent SurrealDB EVENT retries for non-transient errors
117→      return jsonResponse({ status: "error", message: "processing failed" }, 200);
118→    }
119→  };
120→}
121→
122→// ---------------------------------------------------------------------------
123→// Task verification pipeline (effect shell)
124→// ---------------------------------------------------------------------------
125→
126→async function handleTaskVerification(
127→  deps: ServerDependencies,
128→  taskId: string,
129→  body?: Record<string, unknown>,
130→): Promise<void> {
131→  const { surreal } = deps;
132→
133→  // Resolve workspace from the task record body or by querying
134→  const workspaceId = await resolveWorkspaceId(surreal, "task", taskId, body);
135→  if (!workspaceId) {
136→    logError("observer.task.no_workspace", "Cannot determine workspace for task", { taskId });
137→    return;
138→  }
139→
140→  const workspaceRecord = new RecordId("workspace", workspaceId);
141→
142→  // Delegate to observer agent
143→  const agentOutput = await runObserverAgent({
144→    surreal,
145→    workspaceRecord,
146→    entityTable: "task",
147→    entityId: taskId,
148→    entityBody: body,
149→  });
150→
151→  logInfo("observer.task.verified", "Task verification complete", {
152→    taskId,
153→    verdict: agentOutput.verdict,
154→    observationsCreated: agentOutput.observations_created,
155→    evidence: agentOutput.evidence,
156→  });
157→}
158→
159→// ---------------------------------------------------------------------------
160→// Intent verification pipeline (effect shell)
161→// ---------------------------------------------------------------------------
162→
163→async function handleIntentVerification(
164→  deps: ServerDependencies,
165→  intentId: string,
166→  body?: Record<string, unknown>,
167→): Promise<void> {
168→  const { surreal } = deps;
169→
170→  const workspaceId = await resolveWorkspaceId(surreal, "intent", intentId, body);
171→  if (!workspaceId) {
172→    logError("observer.intent.no_workspace", "Cannot determine workspace for intent", { intentId });
173→    return;
174→  }
175→
176→  const workspaceRecord = new RecordId("workspace", workspaceId);
177→  const intentRecord = new RecordId("intent", intentId);
178→
179→  // Gather intent signals: status and trace presence
180→  const intentSignals = await gatherIntentSignals(surreal, intentId, body);
181→  const verificationResult = compareIntentCompletion(intentSignals);
182→
183→  await persistVerificationObservation(surreal, workspaceRecord, intentRecord, verificationResult);
184→
185→  logInfo("observer.intent.verified", "Intent verification complete", {
186→    intentId,
187→    verdict: verificationResult.verdict,
188→    severity: verificationResult.severity,
189→    verified: verificationResult.verified,
190→  });
191→}
192→
193→async function gatherIntentSignals(
194→  surreal: Surreal,
195→  intentId: string,
196→  body?: Record<string, unknown>,
197→): Promise<IntentSignals> {
198→  // Prefer body (from EVENT payload) for status and goal
199→  const status = (body?.status as string) ?? "unknown";
200→  const goal = (body?.goal as string) ?? "Unknown intent";
201→
202→  // Check if a trace exists
203→  const intentRecord = new RecordId("intent", intentId);
204→  const [traceRows] = await surreal.query<[Array<{ trace_id?: RecordId }>]>(
205→    `SELECT trace_id FROM $intent;`,
206→    { intent: intentRecord },
207→  );
208→
209→  const hasTrace = !!traceRows?.[0]?.trace_id;
210→
211→  return { status, goal, hasTrace };
212→}
