214→// ---------------------------------------------------------------------------
215→// Commit verification pipeline (effect shell)
216→// ---------------------------------------------------------------------------
217→
218→async function handleCommitVerification(
219→  deps: ServerDependencies,
220→  commitId: string,
221→  body?: Record<string, unknown>,
222→): Promise<void> {
223→  const { surreal } = deps;
224→
225→  const workspaceId = await resolveWorkspaceId(surreal, "git_commit", commitId, body);
226→  if (!workspaceId) {
227→    logError("observer.commit.no_workspace", "Cannot determine workspace for commit", { commitId });
228→    return;
229→  }
230→
231→  const workspaceRecord = new RecordId("workspace", workspaceId);
232→  const commitRecord = new RecordId("git_commit", commitId);
233→
234→  // Gather CI signals for this commit
235→  const sha = (body?.sha as string) ?? "";
236→  const repository = (body?.repository as string) ?? "";
237→
238→  const signal = await checkCiStatus({
239→    id: commitRecord,
240→    sha,
241→    repository,
242→  });
243→
244→  const signalsResult = {
245→    signals: [signal],
246→    hasCommits: true,
247→  };
248→
249→  const verificationResult = compareCommitStatus(signalsResult);
250→
251→  await persistVerificationObservation(surreal, workspaceRecord, commitRecord, verificationResult);
252→
253→  logInfo("observer.commit.verified", "Commit verification complete", {
254→    commitId,
255→    verdict: verificationResult.verdict,
256→    severity: verificationResult.severity,
257→    verified: verificationResult.verified,
258→  });
259→}
260→
261→// ---------------------------------------------------------------------------
262→// Decision verification pipeline (effect shell)
263→// ---------------------------------------------------------------------------
264→
265→async function handleDecisionVerification(
266→  deps: ServerDependencies,
267→  decisionId: string,
268→  body?: Record<string, unknown>,
269→): Promise<void> {
270→  const { surreal } = deps;
271→
272→  // Skip initial CREATE events -- only verify actual status transitions (UPDATEs).
273→  // CREATE events have no updated_at field; UPDATE always sets updated_at via time::now().
274→  if (!body?.updated_at) {
275→    logInfo("observer.decision.skipped_create", "Skipping decision CREATE event (not a status transition)", { decisionId });
276→    return;
277→  }
278→
279→  const workspaceId = await resolveWorkspaceId(surreal, "decision", decisionId, body);
280→  if (!workspaceId) {
281→    logError("observer.decision.no_workspace", "Cannot determine workspace for decision", { decisionId });
282→    return;
283→  }
284→
285→  const workspaceRecord = new RecordId("workspace", workspaceId);
286→  const decisionRecord = new RecordId("decision", decisionId);
287→
288→  // Gather decision signals: status, summary, and completed task count
289→  const decisionSignals = await gatherDecisionSignals(surreal, workspaceRecord, body);
290→  const verificationResult = compareDecisionConfirmation(decisionSignals);
291→
292→  await persistVerificationObservation(surreal, workspaceRecord, decisionRecord, verificationResult);
293→
294→  logInfo("observer.decision.verified", "Decision verification complete", {
295→    decisionId,
296→    verdict: verificationResult.verdict,
297→    severity: verificationResult.severity,
298→    verified: verificationResult.verified,
299→  });
300→}
