  1→/**
  2→ * Graph scan: periodic workspace-wide analysis for contradictions and anomalies.
  3→ *
  4→ * Pure query functions that gather scan signals from the workspace graph,
  5→ * then delegate to the observer agent for contradiction analysis.
  6→ *
  7→ * Scan types:
  8→ *   1. Decision-implementation contradictions: confirmed decisions vs completed tasks
  9→ *   2. Stale blocked tasks: tasks blocked longer than threshold (14 days)
 10→ */
 11→
 12→import { RecordId, type Surreal } from "surrealdb";
 13→import { createObservation, listWorkspaceOpenObservations } from "../observation/queries";
 14→import { logInfo, logError } from "../http/observability";
 15→
 16→// ---------------------------------------------------------------------------
 17→// Types
 18→// ---------------------------------------------------------------------------
 19→
 20→export type ConfirmedDecision = {
 21→  id: RecordId<"decision">;
 22→  summary: string;
 23→  rationale?: string;
 24→};
 25→
 26→export type CompletedTask = {
 27→  id: RecordId<"task">;
 28→  title: string;
 29→  description?: string;
 30→};
 31→
 32→export type StaleBlockedTask = {
 33→  id: RecordId<"task">;
 34→  title: string;
 35→  description?: string;
 36→  updated_at: string | Date;
 37→  daysBlocked: number;
 38→};
 39→
 40→export type StatusDriftTask = {
 41→  id: RecordId<"task">;
 42→  title: string;
 43→  status: string;
 44→  dependency: {
 45→    id: RecordId<"task">;
 46→    title: string;
 47→    status: string;
 48→  };
 49→};
 50→
 51→export type GraphScanResult = {
 52→  contradictions_found: number;
 53→  stale_blocked_found: number;
 54→  status_drift_found: number;
 55→  observations_created: number;
 56→};
 57→
 58→// ---------------------------------------------------------------------------
 59→// Configuration
 60→// ---------------------------------------------------------------------------
 61→
 62→const STALE_BLOCKED_THRESHOLD_DAYS = 14;
 63→
 64→// ---------------------------------------------------------------------------
 65→// Graph queries (pure data gathering)
 66→// ---------------------------------------------------------------------------
 67→
 68→async function queryConfirmedDecisions(
 69→  surreal: Surreal,
 70→  workspaceRecord: RecordId<"workspace", string>,
 71→): Promise<ConfirmedDecision[]> {
 72→  const [rows] = await surreal.query<[ConfirmedDecision[]]>(
 73→    `SELECT id, summary, rationale, created_at FROM decision
 74→     WHERE workspace = $ws AND status = "confirmed"
 75→     ORDER BY created_at DESC
 76→     LIMIT 50;`,
 77→    { ws: workspaceRecord },
 78→  );
 79→  return rows ?? [];
 80→}
 81→
 82→async function queryCompletedTasks(
 83→  surreal: Surreal,
 84→  workspaceRecord: RecordId<"workspace", string>,
 85→): Promise<CompletedTask[]> {
 86→  const [rows] = await surreal.query<[CompletedTask[]]>(
 87→    `SELECT id, title, description, updated_at FROM task
 88→     WHERE workspace = $ws AND status IN ["completed", "done"]
 89→     ORDER BY updated_at DESC
 90→     LIMIT 50;`,
 91→    { ws: workspaceRecord },
 92→  );
 93→  return rows ?? [];
 94→}
 95→
 96→async function queryStaleBlockedTasks(
 97→  surreal: Surreal,
 98→  workspaceRecord: RecordId<"workspace", string>,
 99→): Promise<StaleBlockedTask[]> {
100→  const thresholdDate = new Date(
101→    Date.now() - STALE_BLOCKED_THRESHOLD_DAYS * 24 * 60 * 60 * 1000,
102→  );
103→
104→  const [rows] = await surreal.query<
105→    [Array<{ id: RecordId<"task">; title: string; description?: string; updated_at: string }>]
106→  >(
107→    `SELECT id, title, description, updated_at FROM task
108→     WHERE workspace = $ws
109→       AND status = "blocked"
110→       AND updated_at < $threshold
111→     ORDER BY updated_at ASC
112→     LIMIT 50;`,
113→    { ws: workspaceRecord, threshold: thresholdDate },
114→  );
115→
116→  return (rows ?? []).map((row) => {
117→    const updatedAt = new Date(row.updated_at);
118→    const daysBlocked = Math.floor(
119→      (Date.now() - updatedAt.getTime()) / (24 * 60 * 60 * 1000),
120→    );
121→    return { ...row, daysBlocked };
122→  });
123→}
124→
125→async function queryStatusDriftTasks(
126→  surreal: Surreal,
127→  workspaceRecord: RecordId<"workspace", string>,
128→): Promise<StatusDriftTask[]> {
129→  // Two-step approach: first find completed tasks with dependencies,
130→  // then filter for incomplete dependencies in application code
131→  const [rows] = await surreal.query<[Array<{
132→    id: RecordId<"task">;
133→    title: string;
134→    status: string;
135→    dep_ids: RecordId<"task">[];
136→    dep_titles: string[];
137→    dep_statuses: string[];
138→  }>]>(
139→    `SELECT
140→       id, title, status,
141→       ->depends_on->task.id AS dep_ids,
142→       ->depends_on->task.title AS dep_titles,
143→       ->depends_on->task.status AS dep_statuses
144→     FROM task
145→     WHERE workspace = $ws
146→       AND status IN ["completed", "done"]
147→       AND array::len(->depends_on->task) > 0
148→     LIMIT 50;`,
149→    { ws: workspaceRecord },
150→  );
151→
152→  return (rows ?? []).flatMap((row) => {
153→    const depIds = row.dep_ids ?? [];
154→    const depTitles = row.dep_titles ?? [];
155→    const depStatuses = row.dep_statuses ?? [];
156→
157→    const drifts: StatusDriftTask[] = [];
158→    for (let i = 0; i < depIds.length; i++) {
159→      const depStatus = depStatuses[i];
160→      if (depStatus !== "completed" && depStatus !== "done") {
161→        drifts.push({
162→          id: row.id,
163→          title: row.title,
164→          status: row.status,
165→          dependency: {
166→            id: depIds[i],
167→            title: depTitles[i],
168→            status: depStatus,
169→          },
170→        });
171→      }
172→    }
173→    return drifts;
174→  });
175→}
176→
177→// ---------------------------------------------------------------------------
178→// Entity-level deduplication query
179→// ---------------------------------------------------------------------------
180→
181→/**
182→ * Queries existing open observer observations linked to a specific entity.
183→ * Used for entity-level dedup -- if the observer already has an open observation
184→ * on this entity, we skip creating another.
185→ */
186→const ALLOWED_OBSERVER_TABLES = ["project", "feature", "task", "decision", "question", "intent", "git_commit", "observation"];
187→
188→async function queryExistingObserverObservationsForEntity(
189→  surreal: Surreal,
190→  workspaceRecord: RecordId<"workspace", string>,
191→  entityRecord: RecordId<string, string>,
192→): Promise<Array<{ text: string; severity: string; status: string }>> {
193→  if (!ALLOWED_OBSERVER_TABLES.includes(entityRecord.table.name)) {
194→    throw new Error(`Invalid entity table for observer dedup query: ${entityRecord.table.name}`);
195→  }
196→
197→  const [rows] = await surreal.query<[Array<{ text: string; severity: string; status: string }>]>(
198→    `SELECT text, severity, status FROM observation
199→     WHERE workspace = $ws
200→       AND source_agent = "observer_agent"
201→       AND status IN ["open", "acknowledged"]
202→       AND ->observes->${entityRecord.table.name}.id CONTAINS $entity
203→     LIMIT 20;`,
204→    { ws: workspaceRecord, entity: entityRecord },
205→  );
206→  return rows ?? [];
207→}
208→
209→// ---------------------------------------------------------------------------
210→// Contradiction detection (deterministic heuristic)
211→// ---------------------------------------------------------------------------
212→
213→/**
214→ * Simple keyword-based contradiction detection between decisions and tasks.
215→ * Looks for signals that a completed task contradicts a confirmed decision.
216→ *
217→ * Returns pairs of (decision, task) that appear contradictory.
218→ */
219→function detectContradictions(
220→  decisions: ConfirmedDecision[],
221→  tasks: CompletedTask[],
222→): Array<{ decision: ConfirmedDecision; task: CompletedTask }> {
223→  const contradictions: Array<{ decision: ConfirmedDecision; task: CompletedTask }> = [];
224→
225→  for (const decision of decisions) {
226→    const decisionText = decision.summary.toLowerCase();
227→
228→    for (const task of tasks) {
229→      const taskText = `${task.title} ${task.description ?? ""}`.toLowerCase();
230→
231→      // Detect technology contradictions
232→      // e.g., decision says "use tRPC" but task implements "REST" or "Express"
233→      if (detectsTechnologyContradiction(decisionText, taskText)) {
234→        contradictions.push({ decision, task });
235→      }
236→    }
237→  }
238→
239→  return contradictions;
240→}
241→
242→/**
243→ * Detects when a task uses a technology that contradicts a decision mandate.
244→ * Checks known technology pairs (e.g., tRPC vs REST, GraphQL vs REST).
245→ */
246→function detectsTechnologyContradiction(
247→  decisionText: string,
248→  taskText: string,
249→): boolean {
250→  const technologyPairs: Array<{ mandated: string[]; contradicting: string[] }> = [
251→    {
252→      mandated: ["trpc"],
253→      contradicting: ["rest", "express"],
254→    },
255→    {
256→      mandated: ["graphql"],
257→      contradicting: ["rest", "express"],
258→    },
259→    {
260→      mandated: ["typescript"],
261→      contradicting: ["javascript"],
262→    },
263→  ];
264→
265→  for (const pair of technologyPairs) {
266→    const mandatesThis = pair.mandated.some((term) => decisionText.includes(term));
267→    const taskUsesContradicting = pair.contradicting.some((term) => taskText.includes(term));
268→
269→    if (mandatesThis && taskUsesContradicting) {
270→      return true;
271→    }
272→  }
273→
274→  return false;
275→}
276→
277→// ---------------------------------------------------------------------------
278→// Deduplication
279→// ---------------------------------------------------------------------------
280→
281→type ExistingObservation = {
282→  text: string;
283→  severity: string;
284→  status: string;
285→};
286→
287→function isAlreadyObserved(
288→  existingObservations: ExistingObservation[],
289→  newText: string,
290→): boolean {
291→  const normalizedNew = newText.toLowerCase();
292→
293→  return existingObservations.some((obs) => {
294→    if (obs.status === "resolved") return false;
295→    const normalizedExisting = obs.text.toLowerCase();
296→    // Check if the core issue is already covered
297→    return (
298→      normalizedExisting.includes(normalizedNew.slice(0, 40)) ||
299→      normalizedNew.includes(normalizedExisting.slice(0, 40))
300→    );
301→  });
302→}
303→
304→// ---------------------------------------------------------------------------
305→// Scan orchestrator
306→// ---------------------------------------------------------------------------
307→
308→export async function runGraphScan(
309→  surreal: Surreal,
310→  workspaceRecord: RecordId<"workspace", string>,
311→): Promise<GraphScanResult> {
312→  const result: GraphScanResult = {
313→    contradictions_found: 0,
314→    stale_blocked_found: 0,
315→    status_drift_found: 0,
316→    observations_created: 0,
317→  };
318→
319→  // Load existing observations for deduplication
320→  const existingObservations = await listWorkspaceOpenObservations({
321→    surreal,
322→    workspaceRecord,
323→    limit: 100,
324→  });
325→
326→  // 1. Detect decision-implementation contradictions
327→  const [decisions, completedTasks] = await Promise.all([
328→    queryConfirmedDecisions(surreal, workspaceRecord),
329→    queryCompletedTasks(surreal, workspaceRecord),
330→  ]);
331→
332→  const contradictions = detectContradictions(decisions, completedTasks);
333→  result.contradictions_found = contradictions.length;
334→
335→  for (const { decision, task } of contradictions) {
336→    // Entity-level dedup: check if observer already has an open observation on this decision
337→    const existingForDecision = await queryExistingObserverObservationsForEntity(
338→      surreal, workspaceRecord,
339→      decision.id as RecordId<string, string>,
340→    );
341→
342→    const observationText =
343→      `Contradiction detected: Decision "${decision.summary}" conflicts with completed task "${task.title}". ` +
344→      `The task appears to implement an approach that contradicts the confirmed decision.`;
345→
346→    if (existingForDecision.length > 0 || isAlreadyObserved(existingObservations, observationText)) {
347→      logInfo("observer.scan.dedup", "Skipping duplicate contradiction observation", {
348→        decisionId: decision.id.id,
349→        taskId: task.id.id,
350→      });
351→      continue;
352→    }
353→
354→    const now = new Date();
355→    await createObservation({
356→      surreal,
357→      workspaceRecord,
358→      text: observationText,
359→      severity: "conflict",
360→      sourceAgent: "observer_agent",
361→      observationType: "contradiction",
362→      now,
363→      relatedRecord: decision.id as RecordId<"project" | "feature" | "task" | "decision" | "question", string>,
364→    });
365→
366→    result.observations_created += 1;
367→  }
368→
369→  // 2. Detect stale blocked tasks
370→  const staleBlocked = await queryStaleBlockedTasks(surreal, workspaceRecord);
371→  result.stale_blocked_found = staleBlocked.length;
372→
373→  for (const task of staleBlocked) {
374→    // Entity-level dedup: check if observer already has an open observation on this task
375→    const existingForTask = await queryExistingObserverObservationsForEntity(
376→      surreal, workspaceRecord,
377→      task.id as RecordId<string, string>,
378→    );
379→
380→    const observationText =
381→      `Task blocked for ${task.daysBlocked} days: "${task.title}". ` +
382→      `This task has been blocked since ${new Date(task.updated_at).toISOString().slice(0, 10)} ` +
383→      `(exceeds the ${STALE_BLOCKED_THRESHOLD_DAYS}-day threshold).`;
384→
385→    if (existingForTask.length > 0 || isAlreadyObserved(existingObservations, observationText)) {
386→      logInfo("observer.scan.dedup", "Skipping duplicate stale-blocked observation", {
387→        taskId: task.id.id,
388→      });
389→      continue;
390→    }
391→
392→    const now = new Date();
393→    await createObservation({
394→      surreal,
395→      workspaceRecord,
396→      text: observationText,
397→      severity: "warning",
398→      sourceAgent: "observer_agent",
399→      observationType: "anomaly",
400→      now,
401→      relatedRecord: task.id as RecordId<"project" | "feature" | "task" | "decision" | "question", string>,
402→    });
403→
404→    result.observations_created += 1;
405→  }
406→
407→  // 3. Detect status drift (completed tasks with incomplete dependencies)
408→  const driftTasks = await queryStatusDriftTasks(surreal, workspaceRecord);
409→  result.status_drift_found = driftTasks.length;
410→
411→  for (const drift of driftTasks) {
412→    // Entity-level dedup
413→    const existingForTask = await queryExistingObserverObservationsForEntity(
414→      surreal, workspaceRecord,
415→      drift.id as RecordId<string, string>,
416→    );
417→
418→    const observationText =
419→      `Status drift detected: Task "${drift.title}" is marked as ${drift.status}, ` +
420→      `but its dependency "${drift.dependency.title}" is still ${drift.dependency.status}. ` +
421→      `A task should not be completed before its dependencies.`;
422→
423→    if (existingForTask.length > 0 || isAlreadyObserved(existingObservations, observationText)) {
424→      logInfo("observer.scan.dedup", "Skipping duplicate status-drift observation", {
425→        taskId: drift.id.id,
426→        depTaskId: drift.dependency.id.id,
427→      });
428→      continue;
429→    }
430→
431→    const now = new Date();
432→    await createObservation({
433→      surreal,
434→      workspaceRecord,
435→      text: observationText,
436→      severity: "warning",
437→      sourceAgent: "observer_agent",
438→      observationType: "anomaly",
439→      now,
440→      relatedRecord: drift.id as RecordId<"project" | "feature" | "task" | "decision" | "question", string>,
441→    });
442→
443→    result.observations_created += 1;
444→  }
445→
446→  logInfo("observer.scan.completed", "Graph scan completed", {
447→    workspaceId: workspaceRecord.id,
448→    ...result,
449→  });
450→
451→  return result;
452→}
