  1→/**
  2→ * External signal gathering for the observer verification pipeline.
  3→ *
  4→ * Driven port: functions that fetch external CI/GitHub status for commits.
  5→ * Pure types + effect-boundary functions kept separate from domain logic.
  6→ */
  7→import type { Surreal } from "surrealdb";
  8→import { RecordId } from "surrealdb";
  9→import { logError, logInfo } from "../http/observability";
 10→
 11→// ---------------------------------------------------------------------------
 12→// Types
 13→// ---------------------------------------------------------------------------
 14→
 15→export type CiStatus = "success" | "failure" | "pending" | "unknown";
 16→
 17→export type ExternalSignal = {
 18→  sha: string;
 19→  repository: string;
 20→  ciStatus: CiStatus;
 21→  source: string;
 22→};
 23→
 24→export type GatherSignalsResult = {
 25→  signals: ExternalSignal[];
 26→  hasCommits: boolean;
 27→};
 28→
 29→type CommitRecord = {
 30→  id: RecordId<"git_commit", string>;
 31→  sha: string;
 32→  repository?: string;
 33→};
 34→
 35→// ---------------------------------------------------------------------------
 36→// Gather linked commits for a task
 37→// ---------------------------------------------------------------------------
 38→
 39→export async function gatherLinkedCommits(
 40→  surreal: Surreal,
 41→  taskId: string,
 42→): Promise<CommitRecord[]> {
 43→  const taskRecord = new RecordId("task", taskId);
 44→
 45→  // Check source_commit field on the task
 46→  const [taskRows] = await surreal.query<
 47→    [Array<{ source_commit?: RecordId<"git_commit", string> }>]
 48→  >(
 49→    `SELECT source_commit FROM $task;`,
 50→    { task: taskRecord },
 51→  );
 52→
 53→  const sourceCommit = taskRows?.[0]?.source_commit;
 54→  if (!sourceCommit) return [];
 55→
 56→  // Fetch the commit record
 57→  const [commitRows] = await surreal.query<[CommitRecord[]]>(
 58→    `SELECT id, sha, repository FROM $commit;`,
 59→    { commit: sourceCommit },
 60→  );
 61→
 62→  return commitRows ?? [];
 63→}
 64→
 65→// ---------------------------------------------------------------------------
 66→// Check CI status for a commit (GitHub API)
 67→// ---------------------------------------------------------------------------
 68→
 69→export async function checkCiStatus(
 70→  commit: CommitRecord,
 71→): Promise<ExternalSignal> {
 72→  const sha = commit.sha;
 73→  const repository = commit.repository ?? "";
 74→
 75→  if (!repository) {
 76→    return { sha, repository, ciStatus: "unknown", source: "none" };
 77→  }
 78→
 79→  // Attempt GitHub commit status API (configurable base URL for testing)
 80→  const githubBaseUrl = process.env.GITHUB_API_URL ?? "https://api.github.com";
 81→  const githubApiUrl = `${githubBaseUrl}/repos/${repository}/commits/${sha}/status`;
 82→
 83→  try {
 84→    const response = await fetch(githubApiUrl, {
 85→      headers: {
 86→        Accept: "application/vnd.github.v3+json",
 87→        ...(process.env.GITHUB_TOKEN
 88→          ? { Authorization: `Bearer ${process.env.GITHUB_TOKEN}` }
 89→          : {}),
 90→      },
 91→      signal: AbortSignal.timeout(10_000),
 92→    });
 93→
 94→    if (!response.ok) {
 95→      logInfo("observer.ci_check.http_error", "GitHub API returned non-OK", {
 96→        status: response.status,
 97→        sha,
 98→        repository,
 99→      });
100→      return { sha, repository, ciStatus: "unknown", source: "github" };
101→    }
102→
103→    const data = (await response.json()) as { state?: string };
104→    const ciStatus = mapGitHubState(data.state);
105→
106→    return { sha, repository, ciStatus, source: "github" };
107→  } catch (error) {
108→    logError("observer.ci_check.failed", "Failed to check CI status", error);
109→    return { sha, repository, ciStatus: "unknown", source: "github" };
110→  }
111→}
112→
113→function mapGitHubState(state?: string): CiStatus {
114→  switch (state) {
115→    case "success":
116→      return "success";
117→    case "failure":
118→    case "error":
119→      return "failure";
120→    case "pending":
121→      return "pending";
122→    default:
123→      return "unknown";
124→  }
125→}
126→
127→// ---------------------------------------------------------------------------
128→// Gather all external signals for a task
129→// ---------------------------------------------------------------------------
130→
131→export async function gatherTaskSignals(
132→  surreal: Surreal,
133→  taskId: string,
134→): Promise<GatherSignalsResult> {
135→  const commits = await gatherLinkedCommits(surreal, taskId);
136→
137→  if (commits.length === 0) {
138→    return { signals: [], hasCommits: false };
139→  }
140→
141→  const signals = await Promise.all(commits.map(checkCiStatus));
142→  return { signals, hasCommits: true };
143→}
144→

  1→/**
  2→ * Observer agent: verifies entity state changes and surfaces observations.
  3→ *
  4→ * Follows the same structural pattern as agents/pm/agent.ts.
  5→ * Currently operates deterministically using the verification pipeline.
  6→ * Future milestones may introduce LLM-based reasoning via ToolLoopAgent.
  7→ *
  8→ * Pipeline: receive event -> load workspace context -> verify claim vs reality -> create observation
  9→ */
 10→
 11→import { RecordId, type Surreal } from "surrealdb";
 12→import { createObservation } from "../../observation/queries";
 13→import { gatherTaskSignals } from "../../observer/external-signals";
 14→import { compareTaskCompletion, type VerificationResult } from "../../observer/verification-pipeline";
 15→
 16→// ---------------------------------------------------------------------------
 17→// Types
 18→// ---------------------------------------------------------------------------
 19→
 20→export type ObserverVerdict = "match" | "mismatch" | "inconclusive";
 21→
 22→export type ObserverAgentOutput = {
 23→  observations_created: number;
 24→  verdict: ObserverVerdict;
 25→  evidence: string[];
 26→};
 27→
 28→export type ObserverAgentInput = {
 29→  surreal: Surreal;
 30→  workspaceRecord: RecordId<"workspace", string>;
 31→  entityTable: string;
 32→  entityId: string;
 33→  entityBody?: Record<string, unknown>;
 34→};
 35→
 36→// ---------------------------------------------------------------------------
 37→// Agent entry point
 38→// ---------------------------------------------------------------------------
 39→
 40→export async function runObserverAgent(input: ObserverAgentInput): Promise<ObserverAgentOutput> {
 41→  const { surreal, workspaceRecord, entityTable, entityId } = input;
 42→
 43→  // Dispatch to entity-specific verification
 44→  switch (entityTable) {
 45→    case "task":
 46→      return verifyTaskCompletion(surreal, workspaceRecord, entityId);
 47→    default:
 48→      return {
 49→        observations_created: 0,
 50→        verdict: "inconclusive",
 51→        evidence: [`Entity type '${entityTable}' verification not yet implemented`],
 52→      };
 53→  }
 54→}
 55→
 56→// ---------------------------------------------------------------------------
 57→// Task verification
 58→// ---------------------------------------------------------------------------
 59→
 60→async function verifyTaskCompletion(
 61→  surreal: Surreal,
 62→  workspaceRecord: RecordId<"workspace", string>,
 63→  taskId: string,
 64→): Promise<ObserverAgentOutput> {
 65→  const taskRecord = new RecordId("task", taskId);
 66→  const evidence: string[] = [];
 67→
 68→  // Gather external signals (commits, CI)
 69→  const signalsResult = await gatherTaskSignals(surreal, taskId);
 70→  evidence.push(`Commits found: ${signalsResult.hasCommits}`);
 71→  evidence.push(`Signal count: ${signalsResult.signals.length}`);
 72→
 73→  // Run pure comparison
 74→  const verificationResult = compareTaskCompletion(signalsResult);
 75→  evidence.push(`Verdict: ${verificationResult.verdict}`);
 76→  evidence.push(verificationResult.text);
 77→
 78→  // Persist observation with observes edge
 79→  await persistVerificationObservation(
 80→    surreal,
 81→    workspaceRecord,
 82→    taskRecord,
 83→    verificationResult,
 84→  );
 85→
 86→  return {
 87→    observations_created: 1,
 88→    verdict: verificationResult.verdict,
 89→    evidence,
 90→  };
 91→}
 92→
 93→// ---------------------------------------------------------------------------
 94→// Observation persistence
 95→// ---------------------------------------------------------------------------
 96→
 97→async function persistVerificationObservation(
 98→  surreal: Surreal,
 99→  workspaceRecord: RecordId<"workspace", string>,
100→  relatedRecord: RecordId,
101→  verificationResult: VerificationResult,
102→): Promise<void> {
103→  const now = new Date();
104→
105→  const observationRecord = await createObservation({
106→    surreal,
107→    workspaceRecord,
108→    text: verificationResult.text,
109→    severity: verificationResult.severity,
110→    sourceAgent: "observer_agent",
111→    observationType: "validation",
112→    now,
113→    relatedRecord: relatedRecord as RecordId<"project" | "feature" | "task" | "decision" | "question", string>,
114→  });
115→
116→  // Set verified and source fields
117→  await surreal.query(
118→    `UPDATE $obs SET verified = $verified, source = $source;`,
119→    {
120→      obs: observationRecord,
121→      verified: verificationResult.verified,
122→      source: verificationResult.source ?? "none",
123→    },
124→  );
125→}
