 1→/**
 2→ * Observer agent system prompt builder.
 3→ *
 4→ * Loads workspace context including existing observations so the observer
 5→ * can factor them into its analysis (avoids duplicates, builds on prior signals).
 6→ */
 7→
 8→import { RecordId, Surreal } from "surrealdb";
 9→import { listWorkspaceOpenObservations } from "../../observation/queries";
10→
11→function formatObservations(rows: Awaited<ReturnType<typeof listWorkspaceOpenObservations>>): string {
12→  if (rows.length === 0) {
13→    return "- none";
14→  }
15→
16→  return rows
17→    .slice(0, 30)
18→    .map((row) => {
19→      const category = row.category ? `, ${row.category}` : "";
20→      return `- [${row.severity}] ${row.text} (${row.status}, by ${row.sourceAgent}${category})`;
21→    })
22→    .join("\n");
23→}
24→
25→export async function buildObserverSystemPrompt(input: {
26→  surreal: Surreal;
27→  workspaceRecord: RecordId<"workspace", string>;
28→}): Promise<string> {
29→  const [observations] = await Promise.all([
30→    listWorkspaceOpenObservations({
31→      surreal: input.surreal,
32→      workspaceRecord: input.workspaceRecord,
33→      limit: 30,
34→    }),
35→  ]);
36→
37→  return [
38→    "You are the Observer agent.",
39→    "You scan the knowledge graph for patterns, contradictions, stale blockers, and status drift.",
40→    "You create observations to surface risks and signals to other agents and humans.",
41→    "",
42→    "## Architecture: Graph as Communication Bus",
43→    "All agent-to-agent communication happens through the knowledge graph.",
44→    "Other agents (PM, Architect, Coding) write to the same graph.",
45→    "Your observations are visible to all agents in subsequent invocations.",
46→    "",
47→    "## Existing Workspace Observations",
48→    formatObservations(observations),
49→    "",
50→    "## Observation Rules",
51→    "- Create observations for: contradictions between decisions and implementations, stale blocked tasks, status drift, cross-project conflicts.",
52→    "- Set severity to conflict for contradictions, warning for risks, info for awareness.",
53→    "- Do NOT duplicate existing observations. Check the list above before creating new ones.",
54→    "- Always link observations to the entity they concern using related_entity_id.",
55→    "",
56→    "## Verification",
57→    "When verifying task completion or entity state changes:",
58→    "- Check linked commits and CI status when available.",
59→    "- Consider workspace context and existing observations.",
60→    "- Produce a clear verdict: match (verified), mismatch (contradiction found), or inconclusive (insufficient data).",
61→  ].join("\n");
62→}
