  1→export type OpenRouterReasoningEffort = "xhigh" | "high" | "medium" | "low" | "minimal" | "none";
  2→
  3→export type OpenRouterReasoningOptions = {
  4→  enabled?: boolean;
  5→  exclude?: boolean;
  6→  max_tokens?: number;
  7→  effort?: OpenRouterReasoningEffort;
  8→};
  9→
 10→export type ServerConfig = {
 11→  openRouterApiKey: string;
 12→  chatAgentModelId: string;
 13→  extractionModelId: string;
 14→  pmAgentModelId: string;
 15→  analyticsAgentModelId: string;
 16→  embeddingModelId: string;
 17→  embeddingDimension: number;
 18→  extractionStoreThreshold: number;
 19→  extractionDisplayThreshold: number;
 20→  openRouterReasoning?: OpenRouterReasoningOptions;
 21→  surrealUrl: string;
 22→  surrealUsername: string;
 23→  surrealPassword: string;
 24→  surrealNamespace: string;
 25→  surrealDatabase: string;
 26→  port: number;
 27→  githubWebhookSecret?: string;
 28→  betterAuthSecret: string;
 29→  betterAuthUrl: string;
 30→  githubClientId: string;
 31→  githubClientSecret: string;
 32→};
 33→
 34→export function loadServerConfig(): ServerConfig {
 35→  const openRouterApiKey = requireEnv("OPENROUTER_API_KEY");
 36→
 37→  const extractionStoreThreshold = parseUnitInterval(
 38→    requireEnv("EXTRACTION_STORE_THRESHOLD"),
 39→    "EXTRACTION_STORE_THRESHOLD",
 40→  );
 41→
 42→  const extractionDisplayThreshold = parseUnitInterval(
 43→    requireEnv("EXTRACTION_DISPLAY_THRESHOLD"),
 44→    "EXTRACTION_DISPLAY_THRESHOLD",
 45→  );
 46→
 47→  if (extractionDisplayThreshold < extractionStoreThreshold) {
 48→    throw new Error("EXTRACTION_DISPLAY_THRESHOLD must be greater than or equal to EXTRACTION_STORE_THRESHOLD");
 49→  }
 50→
 51→  const chatAgentModelId = requireEnv("CHAT_AGENT_MODEL");
 52→  const extractionModelId = requireEnv("EXTRACTION_MODEL");
 53→  const pmAgentModelId = Bun.env.PM_AGENT_MODEL && Bun.env.PM_AGENT_MODEL.trim().length > 0
 54→    ? Bun.env.PM_AGENT_MODEL.trim()
 55→    : extractionModelId;
 56→  const analyticsAgentModelId = requireEnv("ANALYTICS_MODEL");
 57→  const embeddingModelId = requireEnv("OPENROUTER_EMBEDDING_MODEL");
 58→  const embeddingDimension = parsePositiveInteger(requireEnv("EMBEDDING_DIMENSION"), "EMBEDDING_DIMENSION");
 59→
 60→  const surrealUrl = requireEnv("SURREAL_URL");
 61→  const surrealUsername = requireEnv("SURREAL_USERNAME");
 62→  const surrealPassword = requireEnv("SURREAL_PASSWORD");
 63→  const surrealNamespace = requireEnv("SURREAL_NAMESPACE");
 64→  const surrealDatabase = requireEnv("SURREAL_DATABASE");
 65→
 66→  const port = parsePositiveInteger(requireEnv("PORT"), "PORT");
 67→  const githubWebhookSecret = Bun.env.GITHUB_WEBHOOK_SECRET?.trim() || undefined;
 68→  const betterAuthSecret = requireEnv("BETTER_AUTH_SECRET");
 69→  const betterAuthUrl = requireEnv("BETTER_AUTH_URL");
 70→  const githubClientId = requireEnv("GITHUB_CLIENT_ID");
 71→  const githubClientSecret = requireEnv("GITHUB_CLIENT_SECRET");
 72→
 73→  return {
 74→    openRouterApiKey,
 75→    chatAgentModelId,
 76→    extractionModelId,
 77→    pmAgentModelId,
 78→    analyticsAgentModelId,
 79→    embeddingModelId,
 80→    embeddingDimension,
 81→    extractionStoreThreshold,
 82→    extractionDisplayThreshold,
 83→    openRouterReasoning: parseOpenRouterReasoning(),
 84→    surrealUrl,
 85→    surrealUsername,
 86→    surrealPassword,
 87→    surrealNamespace,
 88→    surrealDatabase,
 89→    port,
 90→    ...(githubWebhookSecret ? { githubWebhookSecret } : {}),
 91→    betterAuthSecret,
 92→    betterAuthUrl,
 93→    githubClientId,
 94→    githubClientSecret,
 95→  };
 96→}
 97→
 98→function requireEnv(name: string): string {
 99→  const value = Bun.env[name];
100→  if (!value || value.trim().length === 0) {
101→    throw new Error(`${name} is required`);
102→  }
103→
104→  return value;
105→}
106→
107→function parsePositiveInteger(value: string, envName: string): number {
108→  const parsed = Number(value);
109→  if (!Number.isInteger(parsed) || parsed < 1) {
110→    throw new Error(`${envName} must be a positive integer`);
111→  }
112→  return parsed;
113→}
114→
115→function parseUnitInterval(value: string, envName: string): number {
116→  const parsed = Number(value);
117→  if (!Number.isFinite(parsed) || parsed < 0 || parsed > 1) {
118→    throw new Error(`${envName} must be a number between 0 and 1`);
119→  }
120→
121→  return parsed;
122→}
123→
124→function parseOpenRouterReasoning(): OpenRouterReasoningOptions | undefined {
125→  const effortValue = Bun.env.OPENROUTER_REASONING_EFFORT;
126→  const maxTokensValue = Bun.env.OPENROUTER_REASONING_MAX_TOKENS;
127→
128→  if (!effortValue && !maxTokensValue) {
129→    return undefined;
130→  }
131→
132→  const reasoning: OpenRouterReasoningOptions = {};
133→
134→  if (effortValue) {
135→    const allowedEfforts: OpenRouterReasoningEffort[] = ["xhigh", "high", "medium", "low", "minimal", "none"];
136→
137→    if (!allowedEfforts.includes(effortValue as OpenRouterReasoningEffort)) {
138→      throw new Error("OPENROUTER_REASONING_EFFORT must be one of xhigh, high, medium, low, minimal, none");
139→    }
140→    reasoning.effort = effortValue as OpenRouterReasoningEffort;
141→  }
142→
143→  if (maxTokensValue) {
144→    const parsed = Number(maxTokensValue);
145→    if (!Number.isFinite(parsed) || parsed < 1) {
146→      throw new Error("OPENROUTER_REASONING_MAX_TOKENS must be a positive number");
147→    }
148→    reasoning.max_tokens = parsed;
149→  }
150→
151→  return reasoning;
152→}
