101→export async function listWorkspaceOpenObservations(input: {
102→  surreal: Surreal;
103→  workspaceRecord: RecordId<"workspace", string>;
104→  limit: number;
105→}): Promise<ObservationSummary[]> {
106→  const [rows] = await input.surreal
107→    .query<[
108→      Array<{
109→        id: ObservationRecord;
110→        text: string;
111→        severity: ObservationSeverity;
112→        status: ObservationStatus;
113→        category?: EntityCategory;
114→        source_agent: string;
115→        created_at: string | Date;
116→      }>,
117→    ]>(
118→      [
119→        "SELECT id, text, severity, status, category, source_agent, created_at",
120→        "FROM observation",
121→        "WHERE workspace = $workspace",
122→        "AND status IN ['open', 'acknowledged']",
123→        "ORDER BY created_at DESC",
124→        "LIMIT $limit;",
125→      ].join(" "),
126→      {
127→        workspace: input.workspaceRecord,
128→        limit: input.limit,
129→      },
130→    )
131→    .collect<[
132→      Array<{
133→        id: ObservationRecord;
134→        text: string;
135→        severity: ObservationSeverity;
136→        status: ObservationStatus;
137→        category?: EntityCategory;
138→        source_agent: string;
139→        created_at: string | Date;
140→      }>,
141→    ]>();
142→
143→  return rows
144→    .slice()
145→    .sort((a, b) => {
146→      const severityDelta = SEVERITY_PRIORITY[a.severity] - SEVERITY_PRIORITY[b.severity];
147→      if (severityDelta !== 0) {
148→        return severityDelta;
149→      }
150→
151→      return new Date(b.created_at).getTime() - new Date(a.created_at).getTime();
152→    })
153→    .map((row) => ({
154→      id: row.id.id as string,
155→      text: row.text,
156→      severity: row.severity,
157→      status: row.status,
158→      ...(row.category ? { category: row.category } : {}),
159→      sourceAgent: row.source_agent,
160→      createdAt: row.created_at instanceof Date ? row.created_at.toISOString() : new Date(row.created_at).toISOString(),
161→    }));
162→}
